mapper.select:
WITH ranked AS ( SELECT l.gym_id, g.name AS gym_name, COUNT(*)::INTEGER AS visit_count, MAX(l.climbed_on) AS latest_visit_date FROM climbing_logs l JOIN gyms g ON g.id = l.gym_id WHERE l.user_id = #{userId} AND l.deleted_at IS NULL
AND l.climbed_on >= #{from}
AND l.climbed_on <= #{to}
GROUP BY l.gym_id, g.name ) SELECT gym_id, gym_name, visit_count, latest_visit_date FROM ranked
WHERE visit_count < #{cursorVisitCount} OR (visit_count = #{cursorVisitCount} AND latest_visit_date < #{cursorLatestVisitDate}) OR (visit_count = #{cursorVisitCount} AND latest_visit_date = #{cursorLatestVisitDate} AND gym_id > #{cursorGymId})
ORDER BY visit_count DESC, latest_visit_date DESC, gym_id ASC LIMIT #{limit}
